instance MotorCurrentThresholdInsight : DTDFVocab:Insight [
    base:desc "Insight indicating when motor current exceeds a configurable threshold."
]

instance MotorAnglePositionInsight : DTDFVocab:Insight [
    base:desc "Insight indicating current motor position relative to safety limits."
]

// Service for data processing
instance DataProcessingService : DTDFVocab:Service [
    base:desc "Service that processes raw sensor data and provides real‑time insights."
